<template>
  <div class="shortcuts-list flex justify-center">
    <div
      data-testid="shortcuts-columns"
      class="grid h-full w-[90%] grid-cols-1 gap-4 md:grid-cols-3 md:gap-24"
    >
      <div
        v-for="(subcategoryCommands, subcategory) in filteredSubcategories"
        :key="subcategory"
        class="flex flex-col"
      >
        <h3
          class="subcategory-title mb-4 text-xs font-bold tracking-wide text-text-secondary uppercase"
        >
          {{ getSubcategoryTitle(subcategory) }}
        </h3>

        <div class="flex flex-col gap-1">
          <div
            v-for="command in subcategoryCommands"
            :key="command.id"
            class="shortcut-item flex items-center justify-between rounded-sm py-2 transition-colors duration-200"
          >
            <div class="shortcut-info grow pr-4">
              <div class="shortcut-name text-sm font-medium">
                {{ t(`commands.${normalizeI18nKey(command.id)}.label`) }}
              </div>
            </div>

            <div class="keybinding-display shrink-0">
              <div
                class="flex flex-wrap items-center justify-end gap-1"
                :aria-label="shortcutAriaLabel(command)"
              >
                <template
                  v-if="
                    keybindingStore.getKeybindingsByCommandId(command.id).length >
                    0
                  "
                >
                  <template
                    v-for="(
                      kb, kbIndex
                    ) in keybindingStore.getKeybindingsByCommandId(command.id)"
                    :key="kb.combo.serialize()"
                  >
                    <span
                      v-if="kbIndex > 0"
                      class="text-xs text-text-secondary"
                      aria-hidden="true"
                      >·</span
                    >
                    <div class="keybinding-combo flex gap-1">
                      <span
                        v-for="key in kb.combo.getKeySequences()"
                        :key="`${kb.combo.serialize()}-${key}`"
                        class="key-badge min-w-6 rounded-sm bg-muted-background px-2 py-1 text-center font-mono text-xs"
                      >
                        {{ formatKey(key) }}
                      </span>
                    </div>
                  </template>
                </template>
                <template
                  v-else-if="
                    allowUnboundWithHint && command.shortcutsPanelHint
                  "
                >
                  <div class="keybinding-combo flex gap-1">
                    <span
                      class="key-badge max-w-[14rem] break-words rounded-sm bg-muted-background px-2 py-1 text-center font-mono text-xs whitespace-normal"
                    >
                      {{ command.shortcutsPanelHint }}
                    </span>
                  </div>
                </template>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { computed } from 'vue'
import { useI18n } from 'vue-i18n'

import { useKeybindingStore } from '@/platform/keybindings/keybindingStore'
import type { ComfyCommandImpl } from '@/stores/commandStore'
import { normalizeI18nKey } from '@/utils/formatUtil'

const { t } = useI18n()
const keybindingStore = useKeybindingStore()

const { subcategories, allowUnboundWithHint = false } = defineProps<{
  subcategories: Record<string, ComfyCommandImpl[]>
  /** When true, rows with `shortcutsPanelHint` (no keybinding) are listed — e.g. mouse gestures. */
  allowUnboundWithHint?: boolean
}>()

const shortcutAriaLabel = (command: ComfyCommandImpl) => {
  const kbs = keybindingStore.getKeybindingsByCommandId(command.id)
  if (kbs.length > 0) {
    const parts = kbs.map((kb) => kb.combo.getKeySequences().join(' + '))
    return `Keyboard shortcut: ${parts.join(' · ')}`
  }
  if (command.shortcutsPanelHint) {
    return `Shortcut: ${command.shortcutsPanelHint}`
  }
  return ''
}

const filteredSubcategories = computed(() => {
  const result: Record<string, ComfyCommandImpl[]> = {}

  for (const [subcategory, commands] of Object.entries(subcategories)) {
    const filtered = commands.filter((cmd) => {
      const kbs = keybindingStore.getKeybindingsByCommandId(cmd.id)
      if (kbs.length > 0) return true
      return !!allowUnboundWithHint && !!cmd.shortcutsPanelHint
    })
    if (filtered.length > 0) {
      result[subcategory] = filtered
    }
  }

  return result
})

const getSubcategoryTitle = (subcategory: string): string => {
  const titleMap: Record<string, string> = {
    workflow: t('shortcuts.subcategories.workflow'),
    node: t('shortcuts.subcategories.node'),
    queue: t('shortcuts.subcategories.queue'),
    view: t('shortcuts.subcategories.view'),
    'panel-controls': t('shortcuts.subcategories.panelControls')
  }

  return titleMap[subcategory] || subcategory
}

const formatKey = (key: string): string => {
  const keyMap: Record<string, string> = {
    Control: 'Ctrl',
    Meta: 'Cmd',
    ArrowUp: '↑',
    ArrowDown: '↓',
    ArrowLeft: '←',
    ArrowRight: '→',
    Backspace: '⌫',
    Delete: '⌦',
    Enter: '↵',
    Escape: 'Esc',
    Tab: '⇥',
    ' ': 'Space'
  }

  return keyMap[key] || key
}
</script>
